import Page from 'components/Page';
import React from 'react';
import {
  Button,
  Card,
  CardBody,
  CardHeader,
  Col,
  Form,
  FormFeedback,
  FormGroup,
  FormText,
  Input,
  Label,
  Row,
  Alert,
  Table,
} from 'reactstrap';
import states from "../api/states";
import yearsofex from "../api/yearsofex";
import { searchStudents,} from "../api/api";
import AsyncStorage from '@callstack/async-storage';
import conf from "../api/config";
import PageSpinner from 'components/PageSpinner';
import MUIDataTable from "mui-datatables";
import CustomToolbarSelectStudentSearch from "../components/CustomToolbarSelectStudentSearch";
class StudentSearchPage extends React.Component {

    constructor(props) {
        super(props);
        this.state = {
          adm : '',
          xtoken:'',
          msg: '',
          error: '',
          preload:false,
          downloadFile:true,
          subjects: [],
          performance: [],
          fees: [],
          hasbooks: [],
          lostbooks: [],
          displinery: [],
        };
        AsyncStorage.getItem(conf.secret)
        .then((results) => {
          if( results !== null )
          {
            let obje_results = JSON.parse(results);
            this.setState({
              ...this.state,
              xtoken : obje_results.user.token,
            });
          }
        })
        .catch((error) => {
          console.log('storage error', error);
        });
    }
    componentDidMount() {
    }
    handleAdmNoInput = (event) => {
        const v = event.target.value;
        this.setState({...this.state, adm: v,});
    }
    handleSaveChanges = () => {
        // console.log('so far', this.state);
        this.setState({
          ...this.state,
          preload:true,
        });
        searchStudents(this.state.xtoken, this.state)
        .then((response) => {
            // console.log('so_far', response);
            if( response.status === 200)
            {
                this.setState({
                    ...this.state,
                    msg: response.message,
                    data: response.data,
                    error: '',
                    preload:false,
                });
            }
            else
            {
                this.setState({
                    ...this.state,
                    error: response.message,
                    msg: '',
                    preload:true,
                });
            }
        })
        .catch((error) => {
            this.setState({
                ...this.state,
                error: 'Connection error occured',
                preload:true,
            });
            console.log('error', error);
        });
    }
    render() {

        const subject_columns = [
            {
              name: 'Id',
              options: {
                display: false
              }
            },
            'Student',
            'Year',
            'Date Enrolled',
        ];
        const perf_columns = [
            {
              name: 'Id',
              options: {
                display: false
              }
            },
            'Student',
            'Year',
            'Date Enrolled',
        ];

        const subject_data2 = () => {
          let rtn = [];
          this.state.subjects.map(item => {
            rtn.push([
                item.id,
                item.slabel,
                item.year,
                item.dlabel,
            ]);
          });
          return rtn;
        }
        const perf_data2 = () => {
            let rtn = [];
            this.state.performance.map(item => {
              rtn.push([
                  item.id,
                  item.slabel,
                  item.year,
                  item.dlabel,
              ]);
            });
            return rtn;
          }
      
        const subject_options = {
            filter: true,
            selectableRows: false,
            selectableRowsOnClick:true,
            filterType: 'dropdown',
            responsive: 'vertical',
            draggableColumns: {
              enabled: true
            },
            rowsPerPage: 5,
            selectToolbarPlacement: 'replace',
            downloadOptions: {
                filename: 'school-report-format.csv',
                separator: ';',
                filterOptions: {
                  useDisplayedColumnsOnly: true,
                  useDisplayedRowsOnly: true,
                }
            },
            onDownload: (buildHead, buildBody, columns, subject_data2) => {
              if (this.state.downloadFile) {
                let val= `${buildHead(columns)}${buildBody(subject_data2)}`.trim();
                return val;
              }
              return false;
            },
        };
        const perf_options = {
            filter: true,
            selectableRows: false,
            selectableRowsOnClick:true,
            filterType: 'dropdown',
            responsive: 'vertical',
            draggableColumns: {
              enabled: true
            },
            rowsPerPage: 5,
            selectToolbarPlacement: 'replace',
            downloadOptions: {
                filename: 'school-report-format.csv',
                separator: ';',
                filterOptions: {
                  useDisplayedColumnsOnly: true,
                  useDisplayedRowsOnly: true,
                }
            },
            onDownload: (buildHead, buildBody, columns, perf_data2) => {
              if (this.state.downloadFile) {
                let val= `${buildHead(columns)}${buildBody(perf_data2)}`.trim();
                return val;
              }
              return false;
            },
        };
      return (
        <Page title="Search Students" breadcrumbs={[{ name: 'Search', active: true }]}>
          <Row>
            <Col xl={12} lg={12} md={12}>
              <Card>
                <CardHeader>Search Students {this.state.preload && (<PageSpinner/>)} </CardHeader>
                {this.state.error.length > 0 && (
                    <Alert color="danger">{this.state.error}</Alert>
                )}
                {this.state.msg.length > 0 && (
                    <Alert color="success">{this.state.msg}</Alert>
                )}
              </Card>
            </Col>
          </Row>

          <Row>
            <Col xl={5} lg={12} md={12}>
              <Card>
                <CardBody>
                <Form>
                    <FormGroup>
                      <Label for="exampleSelect">Student Admission Number *</Label>
                      <Input onChange={this.handleAdmNoInput}
                        type="number" 
                        value={this.state.adm}
                        name="frm"
                        placeholder=""
                      />
                    </FormGroup>
                  </Form>
                </CardBody>
              </Card>
            </Col>
            <Col xl={4} lg={12} md={12}>
              <Card>
                <CardBody>
                  <Form>
                    <FormGroup check row>
                        <br></br>
                      <Col sm={{ size: 10, offset: 2 }}>
                        <Button type="button" onClick={this.handleSaveChanges}>Search now</Button>
                      </Col>
                    </FormGroup>
                  </Form>
                </CardBody>
              </Card>
            </Col>
          </Row>

          <Row>
            <Col xl={12} lg={12} md={12}>
              <Card>
                <CardBody>
                    <MUIDataTable title={'Enrolled subjects'}
                    data={this.state.subjects.map(item => {
                      return [
                        item.id,
                        item.slabel,
                        item.year,
                        item.dlabel,
                      ]
                    })} columns={subject_columns} options={subject_options} />
                    
                    <hr></hr>
                    
                    <MUIDataTable title={'Performance'}
                    data={this.state.performance.map(item => {
                      return [
                        item.id,
                        item.slabel,
                        item.year,
                        item.dlabel,
                      ]
                    })} columns={perf_columns} options={perf_options} />
                </CardBody>
              </Card>
            </Col>
          </Row>
    
        </Page>
      );
    }
}
export default StudentSearchPage;
